import React, {useEffect} from "react";
import {
  AboutContent,
  AboutContentBox,
  CircleClick,
  CirclesBox,
  Example,
  ExampleBox,
  Image,
  Name,
  Namebar,
  Namebox,
  Showbar,
  Text,
  Textbar,
  Title,
  Titlebar,
} from "./aboutElements";

import { Parallax } from "react-scroll-parallax";
import Aos from "aos";
import "aos/dist/aos.css";

import circle from "../../images/circle.svg";
import gd from "../../images/gD.png";
import tip from "../../images/tip.png";
import gitfinder from "../../images/gifinder.png";
import sF from "../../images/wA.png";
import ja from "../../images/ja.png";


const About = () => {

  useEffect(() => {
    Aos.init({ duration: 2000 });
  }, []);

  return (
    <>
      <AboutContent name="About me">
        <AboutContentBox>
          <Titlebar data-aos="fade-up" data-aos-delay="200">
            <Title>About</Title>
          </Titlebar>
          <Namebar>
            <Namebox>
              <Image src={ja} data-aos="fade-up" data-aos-delay="500"/>
              <Name data-aos="fade-up" data-aos-delay="700">
                Hi, I am Michał Sukiennik, a Front-end Developer from Lesser
                Poland province. <br /> I design <em>things.</em>
              </Name>
            </Namebox>
          </Namebar>
          <Textbar>
            <Text data-aos="fade-up" data-aos-delay="500">
              I am a multidisciplinary designer. My experience includes UI/UX
              design, product design, marketing design and front-end
              development.
              <br />
              <br />
              As a designer, I put user needs first. I have a passion for
              organized workflows, visual language design, and solving complex
              problems.
              <br />
              <br />I am more hands-on by profession as I have a mechatronics
              qualification, but software development has consumed me enough to
              stay in front of my desk for extended periods of time.
            </Text>
          </Textbar>

          <Showbar>
            <Textbar>
              <Parallax y={[-80, 40]}>
                <Text style={{ zIndex: "3", fontSize: "1em" }}>
                  "The most important thought I had was that I must have
                  something else. I didn't want to be content with the general
                  template. I wanted users to take a trip to see what it is like
                  now and what the user experience will be from today."
                </Text>
              </Parallax>
            </Textbar>


            <CirclesBox>
              <Parallax y={['-200px', '100px']}>
              <CircleClick src={circle}  />
              </Parallax>
            </CirclesBox>

            <ExampleBox top="20%" left="5%">
              <Parallax y={['-100px', '100px']}>
                <Example src={gitfinder} />
              </Parallax>
            </ExampleBox>

            <ExampleBox top="80%" left="20%">
              <Parallax y={['-200px', '100px']}>
                <Example src={gd} />
              </Parallax>
            </ExampleBox>


            <ExampleBox top="30%" left="75%">
              <Parallax y={['-200px', '100px']}>
                <Example src={tip} />
              </Parallax>
            </ExampleBox>

            <ExampleBox top="70%" left="65%">
              <Parallax y={['-200px', '100px']}>
                <Example src={sF} />
              </Parallax>
            </ExampleBox>

          </Showbar>
        </AboutContentBox>
      </AboutContent>
    </>
  );
};

export default About;
