import styled from "styled-components";
import { Link } from "react-scroll";

export const AboutContent = styled.section`
    width: 100%;
    display: flex;
    justify-content: center;    
    align-items: flex-end;
    margin-top: 100px;
`

export const AboutContentBox = styled.div`
    width: 90%;
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    align-items: flex-end;
`

export const Titlebar = styled.div`
    width: 100%;
    display: flex;
    align-items: flex-end;
`

export const Title = styled.h3`
    margin: 0;
    font-size: 10vw;
    color: #ffbd00;
`

export const Namebar = styled.div`
    width: 40%;
    margin-top: 50px;
    display: flex;
    justify-content: flex-end;
    position: relative;

    @media screen and (max-width: 1200px)
    {
        width: 100%;
    }
`



export const Image = styled.img`
    position: absolute;
    bottom: 0;
    left: -300px;
    z-index: 0;
    width: 50%;

    @media screen and (max-width: 1200px)
    {
        left: 150px;
        bottom: 100px;
    }
`

export const Namebox = styled.div`
    width: 100%;
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    align-items: flex-end;
`

export const Name = styled.span`
    margin-top: 40px;
    font-size: 3vw;
    z-index: 1;

    
    @media screen and (max-width: 1200px)
    {   
        margin-top: 0;
        font-size: 8vw;
    }
`

export const Textbar = styled.div`
    width: 40%;
    margin-top: 100px;
    display: flex;
    z-index: 10;
    font-family: 'Poppins', Halvetica, sans-serif;

    @media screen and (max-width: 1200px)
    {
        margin-top: 30px;
        width: 100%;
    }
`

export const Text = styled.span`
    font-size: 2vw;
    text-align: justify;


    @media screen and (max-width: 1200px)
    {
        font-size: 5vw
    }
`
export const Showbar = styled.div`
    width: 100%;
    height: 100vh;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    position: relative;
`
export const CirclesBox = styled(Link)`
  cursor: pointer;
`;

export const CircleClick = styled.img`
  width: 20vh;
  transition: 0.3s;

  &:hover {
    transform: scale(1.4);
  }
`;

export const Example = styled.img`
    position: absolute;
    border-radius: 5px;
    top: ${props => props.top};
    left: ${props => props.left};
    width: 20vw;
    height: 20vh;
    object-fit: cover;
    opacity: 0.7;

    @media screen and (max-width: 1200px)
    {
        width: 130px;
        height: 130px;
        opacity: 0.5;
    }
`

export const ExampleBox = styled.div`
        position: absolute;
    border-radius: 5px;
    top: ${props => props.top};
    left: ${props => props.left};
    width: 20vw;
    object-fit: cover;
    transform: none;

    @media screen and (max-width: 1200px)
    {
        width: 130px;
        height: 130px;
    }
`
